// SPDX-License-Identifier: GPL-3.0
pragma solidity 0.8.15;

contract SubscriptionContract {
    enum planType { standard , pro , premium }  // defining subscription plan options...

    // defining plan type...
    struct plan {
        uint monthlyCost ; // depends on plan...
        planType planName ;
    }

    // defining subscription info type...
    struct subscritionInfo {
        address subscribedBy ;
        plan PlanBought ;
        uint expiry ;
    }

    address payable owner ; // variable storing system owner... 
    uint public totalSubs ;
    mapping(planType => uint256) public planCosts; // storing plan cost...
    mapping (uint => planType) private specificPlan ; // for getting specific plan...
    mapping(address => subscritionInfo) subscriptions ; // storing subscriptions...

    constructor () {
        owner = payable(msg.sender) ; 
        planCosts[planType.standard] = 19 wei;
        planCosts[planType.pro] = 39 wei;
        planCosts[planType.premium] = 99 wei;
    }

    // function giving service based on subscription...
    function subscriptionProtectedService() public view returns(string memory) {
        require( block.timestamp < subscriptions[msg.sender].expiry , "You're subscription is expired , ABORTING !!");
        return "SCAMMED Successfully , FUCK OFF !!" ;
    }

    // function for subscribing to plan...
    function getOrUpdateSubscription(uint _amountpaid) public payable {
        require(_amountpaid == planCosts[planType.standard] || _amountpaid == planCosts[planType.pro] || _amountpaid == planCosts[planType.premium]);
        // making a new subscription...
        if (subscriptions[msg.sender].expiry == 0) {
            plan memory exactPlan = plan( _amountpaid , specificPlan[_amountpaid] );
            subscritionInfo memory newSubs = subscritionInfo( msg.sender , exactPlan , block.timestamp + 2592000 ) ; // 30 days in seconds
            subscriptions[msg.sender] = newSubs ;

            totalSubs++ ;
        }

        // updating the same subscription...
        subscriptions[msg.sender].expiry = block.timestamp + 2592000 ;
    }

    // function for checking account subscription...
    function isAddressSubscribed(address _accountAddess) public view returns(bool) {
        subscritionInfo memory subscObj = subscriptions[_accountAddess] ; // getting the subscription obj...
        // if address is subscribed...

        if (subscObj.expiry != 0) return true ;

        else return false ; // if not subscribed...
        
    }

}

